module traffic_light
(
    input rst_n,
    input clk,
    input pass_request,
    output [7:0] clock,
    output reg red
);
    parameter idle = 2'b00;
    parameter s1_red = 2'b01;
    parameter s2_yellow = 2'b10;
    parameter s3_green = 2'b11;
    reg [1:0] state;
    reg [1:0] next_state;
    reg [7:0] cnt;
    reg [7:0] next_cnt;
    reg next_red;
    reg next_yellow;
    reg next_green;
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state <= idle;
        end else begin
            state <= next_state;
        end
    end
    always @(*) begin
        case (state)
            idle: begin
                next_state = s1_red;
            end
            s1_red: begin
                if (cnt == 60) begin
                    next_state = s3_green;
                end else begin
                    next_state = s1_red;
                end
            end
            s2_yellow: begin
                if (cnt == 5) begin
                    next_state = s1_red;
                end else begin
                    next_state = s2_yellow;
                end
            end
            s3_green: begin
                if (cnt == 10) begin
                    next_state = s2_yellow;
                end else begin
                    next_state = s3_green;
                end
            end
            default: begin
                next_state = idle;
            end
        endcase
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            cnt <= 10;
        end else begin
            cnt <= next_cnt;
        end
    end
    always @(*) begin
        case (cnt)
            10: begin
                if (pass_request) begin
                    next_cnt = 60;
                end else begin
                    next_cnt = 10;
                end
            end
            60: begin
                next_cnt = 5;
            end
            5: begin
                next_cnt = 10;
            end
            1: begin
                next_cnt = 10;
            end
            default: begin
                next_cnt = cnt - 1;
            end
        endcase
    end
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            red <= 0;
            next_yellow = 0;
            next_green = 0;
        end else begin
            red <= next_red;
            yellow <= next_yellow;
            green <= next_green;
        end
    end
    always @(*) begin
        case (state)
            idle: begin
                next_red = 0;
            end
            s1_red: begin
                next_red = 1;
            end
            s2_yellow: begin
                next_yellow = 1;
            end
            s3_green: begin
                next_green = 1;
            end
            default: begin
                next_red = 0;
            end
        endcase
    end
    always @(*) begin
        case (state)
            idle: begin
                next_yellow = 0;
            end
            s1_red: begin
                next_yellow = 0;
            end
            s2_yellow: begin
                next_yellow = 1;
            end
            s3_green: begin
                next_yellow = 0;
            end
            default: begin
                next_yellow = 0;
            end
        endcase
    end
    always @(*) begin
        case (state)
            idle: begin
                next_green = 0;
            end
            s1_red: begin
                next_green = 0;
            end
            s2_yellow: begin
                next_green = 0;
            end
            s3_green: begin
                next_green = 1;
            end
            default: begin
                next_green = 0;
            end
        endcase
    end
endmodule
